    MOON = '''<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 3a6 6 0 0 0 9 9 9 9 0 1 1-9-9Z"/></svg>'''

    @staticmethod
    def get_pixmap(svg_str, size=24, color="#FFFFFF"):
        """Render SVG string to QPixmap with specified color and size."""
        # Inject color into SVG
        colored_svg = svg_str.replace('stroke="currentColor"', f'stroke="{color}"')
        
        renderer = QSvgRenderer(QByteArray(colored_svg.encode('utf-8')))
        pixmap = QPixmap(QSize(size, size))
        pixmap.fill(Qt.transparent)
        
        painter = QPainter(pixmap)
        renderer.render(painter)
        painter.end()
        
        return pixmap

    @staticmethod
    def get_icon(svg_str, size=24, color="#FFFFFF"):
        """Wrapper to get QIcon from SVG."""
        return QIcon(Icons.get_pixmap(svg_str, size, color))
